/**
 * Spatial Indexing Types for PERF-002
 *
 * This module defines interfaces for spatial queries on the canvas.
 * The goal is to efficiently find entities within a viewport region
 * without iterating through all 60k+ tasks.
 *
 * Architecture:
 * - ISpatialIndex: Abstract interface for any spatial index implementation
 * - SimpleSpatialIndex: O(n) placeholder (this PR)
 * - RBushSpatialIndex: Full R-tree implementation (STATE-ARCH-001.Phase2)
 *
 * Coordinate system matches canvas:
 * - X: days from start (positive = future)
 * - Y: train rows (0 = top, negative = down)
 */

import type { TaskRender } from '../data/types';

// ─────────────────────────────────────────────────────────────
// VIEWPORT BOUNDS
// ─────────────────────────────────────────────────────────────

/**
 * Rectangle defining the visible viewport in world coordinates.
 * Used for culling queries - only render entities within these bounds.
 */
export interface ViewportBounds {
  /** Left edge in world X (days * pxPerDay) */
  minX: number;
  /** Right edge in world X */
  maxX: number;
  /** Bottom edge in world Y (negative, more trains) */
  minY: number;
  /** Top edge in world Y (closer to 0) */
  maxY: number;
}

/**
 * Entity bounding box for spatial indexing.
 * Compatible with RBush item format.
 */
export interface SpatialItem {
  /** Left edge */
  minX: number;
  /** Right edge */
  maxX: number;
  /** Bottom edge (lower Y value, more negative) */
  minY: number;
  /** Top edge (higher Y value, closer to 0) */
  maxY: number;
  /** Reference to the entity ID */
  id: string;
}

// ─────────────────────────────────────────────────────────────
// SPATIAL INDEX INTERFACE
// ─────────────────────────────────────────────────────────────

/**
 * Query result with optional distance for nearest-neighbor queries.
 */
export interface SpatialQueryResult {
  /** Entity ID */
  id: string;
  /** Distance from query point (for nearest queries) */
  distance?: number;
}

/**
 * Statistics for monitoring index performance.
 */
export interface SpatialIndexStats {
  /** Total number of indexed items */
  itemCount: number;
  /** Time taken for last bulk load (ms) */
  lastBuildTimeMs?: number;
  /** Time taken for last query (ms) */
  lastQueryTimeMs?: number;
  /** Number of items returned in last query */
  lastQueryResultCount?: number;
}

/**
 * Abstract interface for spatial indexing.
 *
 * This interface is implementation-agnostic - it can be backed by:
 * - SimpleSpatialIndex: O(n) linear scan (placeholder)
 * - RBushSpatialIndex: R-tree for O(log n) queries
 * - FlatbushSpatialIndex: Static R-tree for read-heavy workloads
 * - Custom TypedArray-based index for maximum performance
 *
 * Usage pattern:
 * 1. Create index and load data once (or on data change)
 * 2. Query frequently during pan/zoom
 * 3. Clear and rebuild only when data changes
 */
export interface ISpatialIndex {
  /**
   * Bulk load items into the index.
   * More efficient than inserting one by one.
   *
   * @param items - Array of items to index
   */
  load(items: SpatialItem[]): void;

  /**
   * Insert a single item into the index.
   * Use sparingly - bulk load is more efficient.
   *
   * @param item - Item to insert
   */
  insert(item: SpatialItem): void;

  /**
   * Remove an item from the index by ID.
   *
   * @param id - ID of item to remove
   * @returns true if item was found and removed
   */
  remove(id: string): boolean;

  /**
   * Clear all items from the index.
   */
  clear(): void;

  /**
   * Query items within viewport bounds.
   * This is the main query used for viewport culling.
   *
   * @param bounds - Viewport rectangle in world coordinates
   * @returns Array of item IDs within bounds
   */
  queryViewport(bounds: ViewportBounds): string[];

  /**
   * Query items within a circular region.
   * Useful for mouse hover detection.
   *
   * @param x - Center X in world coordinates
   * @param y - Center Y in world coordinates
   * @param radius - Search radius in world units
   * @returns Array of item IDs within radius
   */
  queryRadius(x: number, y: number, radius: number): string[];

  /**
   * Find the nearest item to a point.
   * Useful for snapping and selection.
   *
   * @param x - Query X in world coordinates
   * @param y - Query Y in world coordinates
   * @param maxDistance - Maximum search distance (optional)
   * @returns Nearest item ID and distance, or null if none found
   */
  queryNearest(x: number, y: number, maxDistance?: number): SpatialQueryResult | null;

  /**
   * Get performance statistics.
   */
  getStats(): SpatialIndexStats;
}

// ─────────────────────────────────────────────────────────────
// HELPER FUNCTIONS
// ─────────────────────────────────────────────────────────────

/**
 * Convert a TaskRender to a SpatialItem for indexing.
 *
 * @param task - Task with render coordinates
 * @param pxPerDay - Pixels per day (default: 10)
 * @param pxPerTrain - Pixels per train row (default: 24)
 * @returns SpatialItem for indexing
 */
export function taskToSpatialItem(
  task: TaskRender,
  pxPerDay: number = 10,
  pxPerTrain: number = 24
): SpatialItem {
  const minX = task.startDay * pxPerDay;
  const maxX = (task.startDay + task.duration) * pxPerDay;
  // Y is negative (trains go downward from 0)
  const maxY = -task.trainIndex * pxPerTrain;
  const minY = maxY - pxPerTrain;

  return {
    minX,
    maxX,
    minY,
    maxY,
    id: task.id,
  };
}

/**
 * Convert an array of TaskRender to SpatialItems.
 *
 * @param tasks - Array of tasks
 * @param pxPerDay - Pixels per day
 * @param pxPerTrain - Pixels per train row
 * @returns Array of SpatialItems
 */
export function tasksToSpatialItems(
  tasks: TaskRender[],
  pxPerDay: number = 10,
  pxPerTrain: number = 24
): SpatialItem[] {
  return tasks.map(task => taskToSpatialItem(task, pxPerDay, pxPerTrain));
}

/**
 * Check if two rectangles intersect.
 *
 * @param a - First rectangle
 * @param b - Second rectangle
 * @returns true if rectangles overlap
 */
export function rectanglesIntersect(
  a: { minX: number; maxX: number; minY: number; maxY: number },
  b: { minX: number; maxX: number; minY: number; maxY: number }
): boolean {
  return a.minX <= b.maxX && a.maxX >= b.minX && a.minY <= b.maxY && a.maxY >= b.minY;
}

/**
 * Calculate distance from a point to the center of a rectangle.
 *
 * @param px - Point X
 * @param py - Point Y
 * @param rect - Rectangle
 * @returns Distance to center
 */
export function distanceToCenter(
  px: number,
  py: number,
  rect: { minX: number; maxX: number; minY: number; maxY: number }
): number {
  const cx = (rect.minX + rect.maxX) / 2;
  const cy = (rect.minY + rect.maxY) / 2;
  return Math.sqrt((px - cx) ** 2 + (py - cy) ** 2);
}

