/**
 * SimpleSpatialIndex - O(n) Placeholder Implementation
 *
 * This is a simple linear scan implementation of ISpatialIndex.
 * It serves as a placeholder until STATE-ARCH-001.Phase2 implements
 * the full RBush-based spatial index with TypedArray backing.
 *
 * Performance characteristics:
 * - load(): O(n)
 * - insert(): O(1)
 * - remove(): O(n)
 * - queryViewport(): O(n) - iterates all items
 * - queryRadius(): O(n)
 * - queryNearest(): O(n)
 *
 * For 60k tasks, this is acceptable for now but will be replaced
 * with O(log n) R-tree queries in the future.
 *
 * @see STATE-ARCH-001.Phase2 for the optimized implementation
 */

import type {
  ISpatialIndex,
  SpatialItem,
  SpatialIndexStats,
  SpatialQueryResult,
  ViewportBounds,
} from './types';
import { rectanglesIntersect, distanceToCenter } from './types';

export class SimpleSpatialIndex implements ISpatialIndex {
  private items: Map<string, SpatialItem> = new Map();
  private stats: SpatialIndexStats = {
    itemCount: 0,
  };

  /**
   * Bulk load items into the index.
   * For SimpleSpatialIndex, this just stores items in a Map.
   */
  load(items: SpatialItem[]): void {
    const startTime = performance.now();

    this.items.clear();
    for (const item of items) {
      this.items.set(item.id, item);
    }

    this.stats.itemCount = this.items.size;
    this.stats.lastBuildTimeMs = performance.now() - startTime;
  }

  /**
   * Insert a single item.
   */
  insert(item: SpatialItem): void {
    this.items.set(item.id, item);
    this.stats.itemCount = this.items.size;
  }

  /**
   * Remove an item by ID.
   */
  remove(id: string): boolean {
    const deleted = this.items.delete(id);
    this.stats.itemCount = this.items.size;
    return deleted;
  }

  /**
   * Clear all items.
   */
  clear(): void {
    this.items.clear();
    this.stats.itemCount = 0;
  }

  /**
   * Query items within viewport bounds.
   * O(n) linear scan - checks all items for intersection.
   *
   * This is the hot path that will be optimized in STATE-ARCH-001.
   */
  queryViewport(bounds: ViewportBounds): string[] {
    const startTime = performance.now();
    const results: string[] = [];

    for (const item of this.items.values()) {
      if (rectanglesIntersect(item, bounds)) {
        results.push(item.id);
      }
    }

    this.stats.lastQueryTimeMs = performance.now() - startTime;
    this.stats.lastQueryResultCount = results.length;

    return results;
  }

  /**
   * Query items within a circular region.
   * O(n) - checks all items.
   */
  queryRadius(x: number, y: number, radius: number): string[] {
    const startTime = performance.now();
    const results: string[] = [];
    const radiusSq = radius * radius;

    for (const item of this.items.values()) {
      // Check if circle intersects rectangle
      // Find closest point on rectangle to circle center
      const closestX = Math.max(item.minX, Math.min(x, item.maxX));
      const closestY = Math.max(item.minY, Math.min(y, item.maxY));

      const distSq = (x - closestX) ** 2 + (y - closestY) ** 2;
      if (distSq <= radiusSq) {
        results.push(item.id);
      }
    }

    this.stats.lastQueryTimeMs = performance.now() - startTime;
    this.stats.lastQueryResultCount = results.length;

    return results;
  }

  /**
   * Find the nearest item to a point.
   * O(n) - checks all items.
   */
  queryNearest(x: number, y: number, maxDistance?: number): SpatialQueryResult | null {
    const startTime = performance.now();
    let nearest: SpatialQueryResult | null = null;
    let minDistSq = maxDistance !== undefined ? maxDistance * maxDistance : Infinity;

    for (const item of this.items.values()) {
      // Distance from point to rectangle center
      const dist = distanceToCenter(x, y, item);
      const distSq = dist * dist;

      if (distSq < minDistSq) {
        minDistSq = distSq;
        nearest = {
          id: item.id,
          distance: dist,
        };
      }
    }

    this.stats.lastQueryTimeMs = performance.now() - startTime;
    this.stats.lastQueryResultCount = nearest ? 1 : 0;

    return nearest;
  }

  /**
   * Get performance statistics.
   */
  getStats(): SpatialIndexStats {
    return { ...this.stats };
  }

  /**
   * Get an item by ID (useful for debugging).
   */
  getItem(id: string): SpatialItem | undefined {
    return this.items.get(id);
  }

  /**
   * Get all items (useful for debugging).
   */
  getAllItems(): SpatialItem[] {
    return Array.from(this.items.values());
  }
}

/**
 * Create a new SimpleSpatialIndex instance.
 * Factory function for consistent API.
 */
export function createSimpleSpatialIndex(): ISpatialIndex {
  return new SimpleSpatialIndex();
}

