/**
 * MesoLayer - DNA-like task block visualization
 *
 * Renders task blocks using InstancedMesh for optimal performance.
 * Visible at zoom levels 0.5x - 2.0x (MESO LOD level).
 *
 * Features:
 * - InstancedMesh for all task blocks (single draw call)
 * - Color coding: blue (maintenance), orange (overhaul), gray (inspection)
 * - Conflict indicators: red border effect on hasConflict tasks
 * - Alternating row backgrounds for readability
 */

import { useMemo, useRef, useEffect } from 'react';
import { InstancedMesh, Object3D, Color, Matrix4 } from 'three';
import type { TaskRender } from '../../data/types';
import { DEFAULT_VIEW_CONFIG } from '../../data/types';

interface MesoLayerProps {
  tasks: TaskRender[];
  trainCount: number;
  /** Opacity for LOD transitions (0-1). Default: 1 */
  opacity?: number;
  /** Currently hovered task ID for highlight effect */
  hoveredTaskId?: string | null;
  /** Currently selected task ID for selection highlight (F019) */
  selectedTaskId?: string | null;
  /** Currently keyboard-focused task ID for focus indicator (F021) */
  focusedTaskId?: string | null;
}

// Color palette matching POC reference
const COLORS: Record<string, string> = {
  blue: '#3b82f6',    // maintenance
  orange: '#f59e0b',  // overhaul
  gray: '#9ca3af',    // inspection
};

const CONFLICT_COLOR = '#ef4444'; // red for conflicts

// Row background colors (alternating)
const ROW_BG_EVEN = '#ffffff';
const ROW_BG_ODD = '#f8fafc';

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;

// Task block height (with padding)
const TASK_HEIGHT = pxPerTrain - 4; // 20px height with 2px padding top/bottom
const TASK_PADDING_Y = 2;

/**
 * Renders alternating row backgrounds for train rows using InstancedMesh
 * OPTIMIZED: Single draw call instead of 50 individual meshes
 */
function RowBackgrounds({
  trainCount,
  totalDays,
  opacity = 1,
}: {
  trainCount: number;
  totalDays: number;
  opacity?: number;
}) {
  const totalWidth = totalDays * pxPerDay;
  const meshRef = useRef<InstancedMesh>(null);
  const tempObject = useMemo(() => new Object3D(), []);

  useEffect(() => {
    if (!meshRef.current || trainCount === 0) return;

    const mesh = meshRef.current;

    for (let i = 0; i < trainCount; i++) {
      tempObject.position.set(
        totalWidth / 2, // Center the row
        -i * pxPerTrain - pxPerTrain / 2, // Y position (negative = down)
        -0.1 // Behind tasks
      );
      tempObject.scale.set(totalWidth, pxPerTrain, 1);
      tempObject.updateMatrix();
      mesh.setMatrixAt(i, tempObject.matrix);
      mesh.setColorAt(i, new Color(i % 2 === 0 ? ROW_BG_EVEN : ROW_BG_ODD));
    }

    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) {
      mesh.instanceColor.needsUpdate = true;
    }
  }, [trainCount, totalWidth, tempObject]);

  if (trainCount === 0) return null;

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, trainCount]}>
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial transparent opacity={0.5 * opacity} />
    </instancedMesh>
  );
}

// Highlight color multiplier for hovered tasks
// Using high value for clear visual feedback
const HOVER_BRIGHTNESS = 1.8;

// Selection indicator color (distinct cyan/teal)
const SELECTION_COLOR = '#06b6d4'; // cyan-500

// Focus indicator color (F021 - keyboard focus)
// Using a distinct purple for focus to differentiate from selection
const FOCUS_COLOR = '#8b5cf6'; // violet-500

/**
 * Brighten a color for hover effect
 */
function brightenColor(hexColor: string, factor: number): Color {
  const color = new Color(hexColor);
  color.r = Math.min(1, color.r * factor);
  color.g = Math.min(1, color.g * factor);
  color.b = Math.min(1, color.b * factor);
  return color;
}

/**
 * Main task blocks using InstancedMesh
 */
function TaskBlocks({
  tasks,
  opacity = 1,
  hoveredTaskId,
  selectedTaskId,
  focusedTaskId,
}: {
  tasks: TaskRender[];
  opacity?: number;
  hoveredTaskId?: string | null;
  selectedTaskId?: string | null;
  focusedTaskId?: string | null;
}) {
  const meshRef = useRef<InstancedMesh>(null);
  const tempObject = useMemo(() => new Object3D(), []);
  const tempColor = useMemo(() => new Color(), []);

  // Update instance matrices and colors when tasks change or hover/selection/focus changes
  useEffect(() => {
    if (!meshRef.current) return;

    const mesh = meshRef.current;

    tasks.forEach((task, i) => {
      // Calculate position and size
      const width = task.duration * pxPerDay;
      const height = TASK_HEIGHT;
      const x = task.startDay * pxPerDay + width / 2; // Center of task
      const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2; // Negative Y (down)
      // Z ordering: selected > focused > conflict > hovered > normal
      const isSelected = task.id === selectedTaskId;
      const isFocused = task.id === focusedTaskId;
      const isHovered = task.id === hoveredTaskId;
      const z = isSelected ? 0.2 : isFocused ? 0.15 : task.hasConflict ? 0.1 : isHovered ? 0.05 : 0;

      // Set transform
      tempObject.position.set(x, y, z);
      tempObject.scale.set(width, height, 1);
      tempObject.updateMatrix();
      mesh.setMatrixAt(i, tempObject.matrix);

      // Set color: selected gets distinct color, focused gets focus color, hovered gets brightened, normal is base
      if (isSelected) {
        tempColor.set(SELECTION_COLOR);
        mesh.setColorAt(i, tempColor);
      } else if (isFocused) {
        // Focus uses a distinct purple color to differentiate from selection and hover
        tempColor.set(FOCUS_COLOR);
        mesh.setColorAt(i, tempColor);
      } else if (isHovered) {
        const baseColor = task.hasConflict ? CONFLICT_COLOR : COLORS[task.color];
        const brightened = brightenColor(baseColor, HOVER_BRIGHTNESS);
        mesh.setColorAt(i, brightened);
      } else {
        const baseColor = task.hasConflict ? CONFLICT_COLOR : COLORS[task.color];
        tempColor.set(baseColor);
        mesh.setColorAt(i, tempColor);
      }
    });

    // Mark buffers for update
    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) {
      mesh.instanceColor.needsUpdate = true;
    }
  }, [tasks, tempObject, tempColor, hoveredTaskId, selectedTaskId, focusedTaskId]);

  if (tasks.length === 0) {
    return null;
  }

  return (
    <instancedMesh
      ref={meshRef}
      args={[undefined, undefined, tasks.length]}
    >
      {/* Unit plane centered at origin - will be scaled by instance matrix */}
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial toneMapped={false} transparent={opacity < 1} opacity={opacity} />
    </instancedMesh>
  );
}

/**
 * Conflict glow effect layer
 * Renders a subtle glow behind conflict tasks
 */
function ConflictGlows({ tasks, opacity = 1 }: { tasks: TaskRender[]; opacity?: number }) {
  const conflictTasks = useMemo(
    () => tasks.filter((t) => t.hasConflict),
    [tasks]
  );

  const meshRef = useRef<InstancedMesh>(null);
  const tempObject = useMemo(() => new Object3D(), []);

  useEffect(() => {
    if (!meshRef.current || conflictTasks.length === 0) return;

    const mesh = meshRef.current;

    conflictTasks.forEach((task, i) => {
      const width = task.duration * pxPerDay + 6; // Slightly larger for glow
      const height = TASK_HEIGHT + 6;
      const x = task.startDay * pxPerDay + (task.duration * pxPerDay) / 2;
      const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
      const z = -0.05; // Behind the task block

      tempObject.position.set(x, y, z);
      tempObject.scale.set(width, height, 1);
      tempObject.updateMatrix();
      mesh.setMatrixAt(i, tempObject.matrix);
    });

    mesh.instanceMatrix.needsUpdate = true;
  }, [conflictTasks, tempObject]);

  if (conflictTasks.length === 0) {
    return null;
  }

  return (
    <instancedMesh
      ref={meshRef}
      args={[undefined, undefined, conflictTasks.length]}
    >
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial
        color={CONFLICT_COLOR}
        transparent
        opacity={0.3 * opacity}
      />
    </instancedMesh>
  );
}

/**
 * Focus ring effect layer (F021)
 * Renders a pulsing ring around the focused task for accessibility
 */
function FocusRing({
  tasks,
  focusedTaskId,
  opacity = 1,
}: {
  tasks: TaskRender[];
  focusedTaskId: string | null;
  opacity?: number;
}) {
  const focusedTask = useMemo(
    () => (focusedTaskId ? tasks.find((t) => t.id === focusedTaskId) : null),
    [tasks, focusedTaskId]
  );

  const meshRef = useRef<InstancedMesh>(null);
  const tempObject = useMemo(() => new Object3D(), []);

  useEffect(() => {
    if (!meshRef.current) return;

    const mesh = meshRef.current;

    if (focusedTask) {
      const width = focusedTask.duration * pxPerDay + 8; // Larger for ring effect
      const height = TASK_HEIGHT + 8;
      const x = focusedTask.startDay * pxPerDay + (focusedTask.duration * pxPerDay) / 2;
      const y = -focusedTask.trainIndex * pxPerTrain - pxPerTrain / 2;
      const z = 0.12; // Between focus and conflict glows

      tempObject.position.set(x, y, z);
      tempObject.scale.set(width, height, 1);
      tempObject.updateMatrix();
      mesh.setMatrixAt(0, tempObject.matrix);
    } else {
      // Hide the ring by scaling to zero
      tempObject.scale.set(0, 0, 1);
      tempObject.updateMatrix();
      mesh.setMatrixAt(0, tempObject.matrix);
    }

    mesh.instanceMatrix.needsUpdate = true;
  }, [focusedTask, tempObject]);

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, 1]}>
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial
        color={FOCUS_COLOR}
        transparent
        opacity={0.4 * opacity}
      />
    </instancedMesh>
  );
}

/**
 * MesoLayer Component
 *
 * Renders the DNA-like task block visualization for the MESO LOD level.
 */
export function MesoLayer({ tasks, trainCount, opacity = 1, hoveredTaskId, selectedTaskId, focusedTaskId }: MesoLayerProps) {
  // Calculate total days for row backgrounds
  const totalDays = useMemo(() => {
    if (tasks.length === 0) return 365 * 10; // Default: 10 years
    const maxDay = Math.max(...tasks.map((t) => t.startDay + t.duration));
    return Math.max(maxDay + 30, 365 * 10); // Add padding
  }, [tasks]);

  return (
    <group>
      {/* Row backgrounds (behind everything) */}
      <RowBackgrounds trainCount={trainCount} totalDays={totalDays} opacity={opacity} />

      {/* Conflict glow effects (behind task blocks) */}
      <ConflictGlows tasks={tasks} opacity={opacity} />

      {/* Focus ring effect (F021 - behind focused task block) */}
      <FocusRing tasks={tasks} focusedTaskId={focusedTaskId ?? null} opacity={opacity} />

      {/* Main task blocks */}
      <TaskBlocks
        tasks={tasks}
        opacity={opacity}
        hoveredTaskId={hoveredTaskId}
        selectedTaskId={selectedTaskId}
        focusedTaskId={focusedTaskId}
      />
    </group>
  );
}

