     1→/**
     2→ * MMS Data Types
     3→ *
     4→ * Architecture: Persistence vs Rendering
     5→ *
     6→ * Data flows through two distinct layers:
     7→ *
     8→ * Persistent (JSON/API) → Runtime (in memory) → Rendering (canvas)
     9→ *   startDate: string      (Date objects)       startDay: 74
    10→ *   "2024-03-15"           for logic            trainIndex: 5
    11→ *
    12→ * Why this separation?
    13→ * - Date objects cannot be serialized to JSON (become {})
    14→ * - Canvas needs numeric offsets for position calculations
    15→ * - Domain logic needs semantic dates for business rules
    16→ */
    17→
    18→// ─────────────────────────────────────────────────────────────
    19→// ENUMS & CONSTANTS
    20→// ─────────────────────────────────────────────────────────────
    21→
    22→export type AssetType = 'ALSTOM' | 'KINKI';
    23→export type TaskType = 'maintenance' | 'overhaul' | 'inspection';
    24→export type MaintenanceLevel = 'A' | 'B' | 'C' | 'D';
    25→
    26→// ─────────────────────────────────────────────────────────────
    27→// DOMAIN TYPES (Persistent/Serializable)
    28→// These types can be saved to JSON, sent via API, or stored in localStorage.
    29→// ─────────────────────────────────────────────────────────────
    30→
    31→export interface Train {
    32→  id: string;              // "TRAIN-001" or "ALT-001"
    33→  name: string;            // Display name
    34→  assetType: AssetType;    // Fleet type
    35→}
    36→
    37→export interface Task {
    38→  id: string;              // Unique identifier
    39→  trainId: string;         // Reference to Train.id
    40→  startDate: string;       // ISO 8601 date: "2024-03-15"
    41→  endDate: string;         // ISO 8601 date: "2024-03-20"
    42→  type: TaskType;          // Visual category
    43→  hasConflict: boolean;    // Conflict indicator
    44→  predecessorId?: string;  // Optional: ID of task that must complete before this one (F023)
    45→}
    46→
    47→export interface DatasetMeta {
    48→  startDate: string;       // ISO 8601: "2024-01-01"
    49→  trainCount: number;      // Number of trains
    50→  years: number;           // Time range in years
    51→}
    52→
    53→export interface GeneratedData {
    54→  trains: Train[];
    55→  tasks: Task[];
    56→  meta: DatasetMeta;
    57→}
    58→
    59→// ─────────────────────────────────────────────────────────────
    60→// RENDERING TYPES (Runtime/Calculated)
    61→// These types are computed when data loads and used by the canvas.
    62→// Never persisted.
    63→// ─────────────────────────────────────────────────────────────
    64→
    65→export type TaskColor = 'blue' | 'orange' | 'gray';
    66→
    67→export interface TaskRender {
    68→  id: string;              // Same as Task.id
    69→  trainIndex: number;      // Y position (0-based index in trains array)
    70→  startDay: number;        // X position (days since meta.startDate)
    71→  duration: number;        // Width (days)
    72→  color: TaskColor;        // Derived from Task.type
    73→  hasConflict: boolean;    // Passthrough from Task
    74→  type: TaskType;          // For label display in MicroLayer
    75→  predecessorId?: string;  // Optional: ID of predecessor task (F023)
    76→}
    77→
    78→export const TYPE_TO_COLOR: Record<TaskType, TaskColor> = {
    79→  maintenance: 'blue',
    80→  overhaul: 'orange',
    81→  inspection: 'gray',
    82→};
    83→
    84→// ─────────────────────────────────────────────────────────────
    85→// WORLD BOUNDS (Navigation limits)
    86→// ─────────────────────────────────────────────────────────────
    87→
    88→/**
    89→ * Defines the navigable world boundaries.
    90→ * Camera will be clamped to these bounds.
    91→ *
    92→ * Coordinate system:
    93→ * - X: 0 = first day, positive = future
    94→ * - Y: 0 = top (TRAIN-001), negative = down (more trains)
    95→ */
    96→export interface WorldBounds {
    97→  minX: number;  // 0 (first day)
    98→  maxX: number;  // totalDays * pxPerDay
    99→  minY: number;  // -trainCount * pxPerTrain (bottom)
   100→  maxY: number;  // 0 (top)
   101→}
   102→
   103→// ─────────────────────────────────────────────────────────────
   104→// CANVAS CONFIGURATION
   105→// ─────────────────────────────────────────────────────────────
   106→
   107→export interface ViewConfig {
   108→  pxPerDay: number;        // Pixels per day (X scale)
   109→  pxPerTrain: number;      // Pixels per train row (Y scale)
   110→  minZoom: number;         // Minimum zoom level
   111→  maxZoom: number;         // Maximum zoom level
   112→  zoomSensitivity: number; // Scroll sensitivity
   113→  lodThresholds: {
   114→    macro: number;         // Below this → MACRO view
   115→    micro: number;         // Above this → MICRO view
   116→  };
   117→}
   118→
   119→export type LODLevel = 'MACRO' | 'MESO' | 'MICRO';
   120→
   121→export interface ViewportState {
   122→  zoom: number;
   123→  panX: number;
   124→  panY: number;
   125→  lod: LODLevel;
   126→}
   127→
   128→// ─────────────────────────────────────────────────────────────
   129→// DEFAULT VALUES
   130→// ─────────────────────────────────────────────────────────────
   131→
   132→export const DEFAULT_VIEW_CONFIG: ViewConfig = {
   133→  pxPerDay: 10,
   134→  pxPerTrain: 24,
   135→  minZoom: 0.1,
   136→  maxZoom: 5,
   137→  zoomSensitivity: 0.002,
   138→  lodThresholds: {
   139→    macro: 0.5,
   140→    micro: 2.0,
   141→  },
   142→};
   143→
   144→export const DEFAULT_DATASET_META: DatasetMeta = {
   145→  startDate: '2024-01-01',
   146→  trainCount: 50,
   147→  years: 10,
   148→};
   149→
   150→/**
   151→ * Calculate world bounds from dataset metadata
   152→ */
