     1→/**
     2→ * TimelineHeader - Displays date labels synced with canvas panX
     3→ *
     4→ * Features:
     5→ * - Adaptive granularity based on zoom level:
     6→ *   - Low zoom (< 0.5): Years
     7→ *   - Medium zoom (0.5-1.5): Months
     8→ *   - High zoom (1.5-3.0): Weeks
     9→ *   - Very high zoom (> 3.0): Days
    10→ * - Labels positioned to align with canvas content
    11→ * - Labels don't overlap (spacing adjusted based on zoom)
    12→ */
    13→
    14→import { useMemo } from 'react';
    15→import { DEFAULT_VIEW_CONFIG, DEFAULT_DATASET_META } from '../data/types';
    16→
    17→interface TimelineHeaderProps {
    18→  /** Left edge of the visible viewport in world X coordinates */
    19→  viewportLeftX: number;
    20→  /** Right edge of the visible viewport in world X coordinates */
    21→  viewportRightX: number;
    22→  /** Current zoom level */
    23→  zoom: number;
    24→  /** Width of the sidebar (to offset the timeline) */
    25→  sidebarWidth: number;
    26→  /** Callback when a date label is clicked (F124: navigation) */
    27→  onDateClick?: (dayOffset: number) => void;
    28→}
    29→
    30→const { pxPerDay } = DEFAULT_VIEW_CONFIG;
    31→const START_DATE = new Date(DEFAULT_DATASET_META.startDate);
    32→
    33→// Format helpers
    34→const formatYear = (date: Date) => date.getFullYear().toString();
    35→const formatMonth = (date: Date) =>
    36→  date.toLocaleDateString('en-US', { month: 'short', year: 'numeric' });
    37→const formatWeek = (date: Date) =>
    38→  date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    39→const formatDay = (date: Date) =>
    40→  date.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' });
    41→
    42→/**
    43→ * Calculate the appropriate granularity based on zoom level
    44→ */
    45→type Granularity = 'year' | 'month' | 'week' | 'day';
    46→
    47→function getGranularity(zoom: number): Granularity {
    48→  if (zoom < 0.5) return 'year';
    49→  if (zoom < 1.5) return 'month';
    50→  if (zoom < 3.0) return 'week';
    51→  return 'day';
    52→}
    53→
    54→/**
    55→ * Get the minimum pixel spacing between labels for each granularity
    56→ */
    57→function getMinLabelSpacing(granularity: Granularity): number {
    58→  switch (granularity) {
    59→    case 'year':
    60→      return 80;
    61→    case 'month':
    62→      return 70;
    63→    case 'week':
    64→      return 60;
    65→    case 'day':
    66→      return 50;
    67→  }
    68→}
    69→
    70→/**
    71→ * Convert world X coordinate to day offset from start date
    72→ */
    73→function worldXToDayOffset(worldX: number): number {
    74→  return Math.floor(worldX / pxPerDay);
    75→}
    76→
    77→/**
    78→ * Convert day offset to world X coordinate
    79→ */
    80→function dayOffsetToWorldX(dayOffset: number): number {
    81→  return dayOffset * pxPerDay;
    82→}
    83→
    84→/**
    85→ * Add days to a date
    86→ */
    87→function addDays(date: Date, days: number): Date {
    88→  const result = new Date(date);
    89→  result.setDate(result.getDate() + days);
    90→  return result;
    91→}
    92→
    93→/**
    94→ * Get the start of a time unit
    95→ */
    96→function getUnitStart(date: Date, granularity: Granularity): Date {
    97→  const result = new Date(date);
    98→  result.setHours(0, 0, 0, 0);
    99→
   100→  switch (granularity) {
   101→    case 'year':
   102→      result.setMonth(0, 1);
   103→      break;
   104→    case 'month':
   105→      result.setDate(1);
   106→      break;
   107→    case 'week':
   108→      // Start of week (Sunday)
   109→      const day = result.getDay();
   110→      result.setDate(result.getDate() - day);
   111→      break;
   112→    case 'day':
   113→      // Already at start of day
   114→      break;
   115→  }
   116→
   117→  return result;
   118→}
   119→
   120→/**
   121→ * Get days until next unit
   122→ */
   123→function getDaysPerUnit(granularity: Granularity): number {
   124→  switch (granularity) {
   125→    case 'year':
   126→      return 365;
   127→    case 'month':
   128→      return 30;
   129→    case 'week':
   130→      return 7;
   131→    case 'day':
   132→      return 1;
   133→  }
   134→}
   135→
   136→/**
   137→ * Advance to next unit
   138→ */
   139→function advanceUnit(date: Date, granularity: Granularity): Date {
   140→  const result = new Date(date);
   141→
   142→  switch (granularity) {
   143→    case 'year':
   144→      result.setFullYear(result.getFullYear() + 1);
   145→      break;
   146→    case 'month':
   147→      result.setMonth(result.getMonth() + 1);
   148→      break;
   149→    case 'week':
   150→      result.setDate(result.getDate() + 7);
   151→      break;
   152→    case 'day':
   153→      result.setDate(result.getDate() + 1);
   154→      break;
   155→  }
   156→
   157→  return result;
   158→}
   159→
   160→/**
   161→ * Format date based on granularity
   162→ */
   163→function formatDate(date: Date, granularity: Granularity): string {
   164→  switch (granularity) {
   165→    case 'year':
   166→      return formatYear(date);
   167→    case 'month':
   168→      return formatMonth(date);
   169→    case 'week':
   170→      return formatWeek(date);
   171→    case 'day':
   172→      return formatDay(date);
   173→  }
   174→}
   175→
   176→interface TimeLabel {
   177→  dayOffset: number;
   178→  worldX: number;
   179→  label: string;
   180→  isMinor: boolean; // For smaller tick marks
   181→}
   182→
   183→/**
   184→ * Generate labels for the visible viewport
   185→ */
   186→function generateLabels(
   187→  viewportLeftX: number,
   188→  viewportRightX: number,
   189→  granularity: Granularity
   190→): TimeLabel[] {
   191→  const labels: TimeLabel[] = [];
   192→
   193→  // Add padding to viewport to show labels near edges
   194→  const padding = getDaysPerUnit(granularity) * pxPerDay * 2;
   195→  const startDayOffset = worldXToDayOffset(viewportLeftX - padding);
   196→  const endDayOffset = worldXToDayOffset(viewportRightX + padding);
   197→
   198→  // Convert to dates
   199→  const startDate = addDays(START_DATE, startDayOffset);
   200→  const endDate = addDays(START_DATE, endDayOffset);
   201→
   202→  // Find the first unit boundary at or before startDate
   203→  let currentDate = getUnitStart(startDate, granularity);
   204→
   205→  // If currentDate is before START_DATE, advance to START_DATE
   206→  if (currentDate < START_DATE) {
   207→    currentDate = getUnitStart(START_DATE, granularity);
   208→    if (currentDate < START_DATE) {
   209→      currentDate = advanceUnit(currentDate, granularity);
   210→    }
   211→  }
   212→
   213→  // Generate labels until we pass endDate
   214→  while (currentDate <= endDate) {
   215→    const dayOffset = Math.round(
   216→      (currentDate.getTime() - START_DATE.getTime()) / (1000 * 60 * 60 * 24)
   217→    );
   218→    const worldX = dayOffsetToWorldX(dayOffset);
   219→
   220→    // Only add labels within reasonable range
   221→    if (worldX >= viewportLeftX - padding && worldX <= viewportRightX + padding) {
   222→      labels.push({
   223→        dayOffset,
   224→        worldX,
   225→        label: formatDate(currentDate, granularity),
   226→        isMinor: false,
   227→      });
   228→    }
   229→
   230→    currentDate = advanceUnit(currentDate, granularity);
   231→  }
   232→
   233→  return labels;
   234→}
   235→
   236→export function TimelineHeader({
   237→  viewportLeftX,
   238→  viewportRightX,
   239→  zoom,
   240→  sidebarWidth,
   241→  onDateClick,
   242→}: TimelineHeaderProps) {
   243→  const granularity = useMemo(() => getGranularity(zoom), [zoom]);
   244→
   245→  const labels = useMemo(
   246→    () => generateLabels(viewportLeftX, viewportRightX, granularity),
   247→    [viewportLeftX, viewportRightX, granularity]
   248→  );
   249→
   250→  // Calculate viewport width with defensive check
   251→  const viewportWidth = viewportRightX - viewportLeftX;
   252→
   253→  // BUG-005: Guard against invalid viewport (e.g., during initialization)
   254→  const isViewportValid = isFinite(viewportWidth) && viewportWidth > 0;
   255→
   256→  return (
   257→    <div
   258→      style={{
   259→        height: 32,
   260→        backgroundColor: '#f5f8fa',
   261→        borderBottom: '1px solid #e1e8ed',
   262→        display: 'flex',
   263→        alignItems: 'center',
