            <div
              style={{
                position: 'absolute',
                left: viewportRect.x,
                top: viewportRect.y,
                width: viewportRect.width,
                height: viewportRect.height,
                background: VIEWPORT_RECT_COLOR,
                border: `2px solid ${VIEWPORT_RECT_BORDER}`,
                borderRadius: 2,
                pointerEvents: 'none',
                boxSizing: 'border-box',
              }}
            />
          </div>

          {/* Scale indicator */}
          <div
            style={{
              marginTop: 4,
              fontSize: 10,
              color: '#999',
              textAlign: 'center',
            }}
          >
            10 years × {trainCount} trains
          </div>
        </Card>
    </div>
  );
}

