  return (
    <div
      style={{
        position: 'absolute',
        bottom: 16,
        right: 16,
        zIndex: 100,
      }}
    >
      <Card
        elevation={2}
        style={{
          padding: MINIMAP_PADDING,
          borderRadius: 6,
        }}
      >
        {/* Header - no close button (Google Maps style) */}
        <div
          style={{
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            marginBottom: 4,
            fontSize: 11,
            color: '#666',
          }}
        >
          <span style={{ fontWeight: 500 }}>Minimap</span>
        </div>

        {/* Minimap canvas */}
        <div
            ref={minimapRef}
            style={{
              width: MINIMAP_WIDTH,
              height: MINIMAP_HEIGHT,
              background: MINIMAP_BG,
              position: 'relative',
              cursor: isDragging ? 'grabbing' : 'pointer',
              borderRadius: 3,
              overflow: 'hidden',
            }}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
          >
            {/* Heatmap cells */}
            <svg
              width={MINIMAP_WIDTH}
              height={MINIMAP_HEIGHT}
              style={{ position: 'absolute', top: 0, left: 0 }}
            >
              {heatmapData.map((row, rowIndex) =>
                row.map((value, colIndex) => {
                  if (value === 0) return null;
                  const normalizedValue = value / maxDensity;
                  return (
                    <rect
                      key={`${rowIndex}-${colIndex}`}
                      x={colIndex * cellWidth}
                      y={rowIndex * cellHeight}
                      width={cellWidth}
                      height={cellHeight}
                      fill={interpolateColor(normalizedValue)}
                      opacity={0.8}
                    />
                  );
                })
              )}
            </svg>

            {/* Viewport rectangle */}
            <div
              style={{
                position: 'absolute',
                left: viewportRect.x,
                top: viewportRect.y,
                width: viewportRect.width,
                height: viewportRect.height,
                background: VIEWPORT_RECT_COLOR,
                border: `2px solid ${VIEWPORT_RECT_BORDER}`,
                borderRadius: 2,
                pointerEvents: 'none',
                boxSizing: 'border-box',
              }}
            />
          </div>

          {/* Scale indicator */}
          <div
            style={{
              marginTop: 4,
              fontSize: 10,
              color: '#999',
              textAlign: 'center',
            }}
          >
            10 years × {trainCount} trains
          </div>
        </Card>
    </div>
  );
}

