     1→/**
     2→ * InfiniteCanvas - Professional-grade pan/zoom canvas
     3→ *
     4→ * Features:
     5→ * - Pan with mouse drag (bounded to world limits)
     6→ * - Zoom with scroll wheel (centers on cursor position)
     7→ * - Initial view shows top-left of data (X=0, Y=0)
     8→ * - Sidebar sync via onViewportChange callback
     9→ *
    10→ * Coordinate System:
    11→ * - X: 0 = first day, positive = future (right)
    12→ * - Y: 0 = first train (TRAIN-001), negative = more trains (down)
    13→ *
    14→ * References:
    15→ * - D3.js zoom: https://d3js.org/d3-zoom
    16→ * - Three.js OrthographicCamera: https://threejs.org/docs/api/en/cameras/OrthographicCamera.html
    17→ * - pixi-viewport: https://github.com/pixijs-userland/pixi-viewport
    18→ */
    19→
    20→import { Canvas, useThree } from '@react-three/fiber';
    21→import { useCallback, useMemo, useEffect, useRef } from 'react';
    22→import { MesoLayer } from './layers/MesoLayer';
    23→import { MacroLayer } from './layers/MacroLayer';
    24→import { MicroLayer } from './layers/MicroLayer';
    25→import { PerfMonitor } from '../components/PerfMonitor';
    26→import type { PerfEvent } from '../components/PerfMonitor';
    27→import { getRenderData } from '../data/generator';
    28→import type { LODLevel, WorldBounds } from '../data/types';
    29→import { DEFAULT_VIEW_CONFIG, calculateWorldBounds } from '../data/types';
    30→import { useCanvasSelector, canvasActions, canvasStore } from '../state';
    31→import { useSpatialIndex, type ISpatialIndex } from '../spatial';
    32→
    33→// ─────────────────────────────────────────────────────────────
    34→// EXPORTED TYPES
    35→// ─────────────────────────────────────────────────────────────
    36→
    37→/**
    38→ * Viewport information passed to parent component
    39→ */
    40→export interface ViewportInfo {
    41→  /** Y coordinate of the TOP of the viewport in world space */
    42→  topY: number;
    43→  /** Left edge of the viewport in world X coordinates */
    44→  leftX: number;
    45→  /** Right edge of the viewport in world X coordinates */
    46→  rightX: number;
    47→}
    48→
    49→/**
    50→ * Viewport bounds in world coordinates
    51→ * Used for frustum culling - only render tasks within these bounds
    52→ */
    53→export interface ViewportBounds {
    54→  minX: number;
    55→  maxX: number;
    56→  minY: number;
    57→  maxY: number;
    58→}
    59→
    60→// ─────────────────────────────────────────────────────────────
    61→// LOD CONFIGURATION
    62→// ─────────────────────────────────────────────────────────────
    63→
    64→/**
    65→ * LOD Transition Configuration
    66→ *
    67→ * Defines blend zones around LOD thresholds for smooth transitions.
    68→ * During blend zones, both adjacent layers render with interpolated opacity.
    69→ */
    70→const LOD_THRESHOLDS = {
    71→  macroToMeso: 0.5,  // Below 0.5 = MACRO
    72→  mesoToMicro: 2.0,  // Above 2.0 = MICRO
    73→};
    74→
    75→// Size of blend zone around each threshold (±this value)
    76→const BLEND_ZONE_SIZE = 0.15;
    77→
    78→/**
    79→ * Calculate layer opacities for smooth LOD transitions
    80→ *
    81→ * Returns opacity values for each layer (0-1).
    82→ * During blend zones, adjacent layers overlap with interpolated opacity.
    83→ */
    84→function calculateLayerOpacities(zoom: number): {
    85→  macro: number;
    86→  meso: number;
    87→  micro: number;
    88→} {
    89→  const { macroToMeso, mesoToMicro } = LOD_THRESHOLDS;
    90→
    91→  // Define blend zone boundaries
    92→  const macroEnd = macroToMeso - BLEND_ZONE_SIZE; // 0.35
    93→  const mesoStart = macroToMeso + BLEND_ZONE_SIZE; // 0.65
    94→  const mesoEnd = mesoToMicro - BLEND_ZONE_SIZE; // 1.85
    95→  const microStart = mesoToMicro + BLEND_ZONE_SIZE; // 2.15
    96→
    97→  let macro = 0;
    98→  let meso = 0;
    99→  let micro = 0;
   100→
   101→  // Calculate MACRO opacity
   102→  if (zoom <= macroEnd) {
   103→    macro = 1;
   104→  } else if (zoom < mesoStart) {
   105→    // Blend zone MACRO → MESO
   106→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
   107→    macro = 1 - t;
   108→  }
   109→
   110→  // Calculate MESO opacity
   111→  if (zoom < macroEnd) {
   112→    meso = 0;
   113→  } else if (zoom < mesoStart) {
   114→    // Blend zone MACRO → MESO
   115→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
   116→    meso = t;
   117→  } else if (zoom <= mesoEnd) {
   118→    meso = 1;
   119→  } else if (zoom < microStart) {
   120→    // Blend zone MESO → MICRO
   121→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
   122→    meso = 1 - t;
   123→  }
   124→
   125→  // Calculate MICRO opacity
   126→  if (zoom <= mesoEnd) {
   127→    micro = 0;
   128→  } else if (zoom < microStart) {
   129→    // Blend zone MESO → MICRO
   130→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
   131→    micro = t;
   132→  } else {
   133→    micro = 1;
   134→  }
   135→
   136→  return { macro, meso, micro };
   137→}
   138→
   139→/**
   140→ * LODLayers - Orchestrates layer rendering with smooth transitions
   141→ *
   142→ * Renders multiple layers simultaneously during blend zones,
   143→ * with opacity interpolation for smooth visual transitions.
   144→ */
   145→function LODLayers({
   146→  tasks,
   147→  trainCount,
   148→  zoom,
   149→  viewportBounds,
   150→  spatialIndex,
   151→  hoveredTaskId,
   152→  selectedTaskId,
   153→  focusedTaskId,
   154→}: {
   155→  tasks: ReturnType<typeof getRenderData>['tasks'];
   156→  trainCount: number;
   157→  zoom: number;
   158→  viewportBounds: ViewportBounds;
   159→  spatialIndex: ISpatialIndex;
   160→  hoveredTaskId: string | null;
   161→  selectedTaskId: string | null;
   162→  focusedTaskId: string | null;
   163→}) {
   164→  const opacities = useMemo(() => calculateLayerOpacities(zoom), [zoom]);
   165→
   166→  return (
   167→    <group>
   168→      {/* Render each layer if opacity > 0 */}
   169→      {opacities.macro > 0 && (
   170→        <MacroLayer
   171→          tasks={tasks}
   172→          trainCount={trainCount}
   173→          opacity={opacities.macro}
   174→        />
   175→      )}
   176→      {opacities.meso > 0 && (
   177→        <MesoLayer
   178→          tasks={tasks}
   179→          trainCount={trainCount}
   180→          opacity={opacities.meso}
   181→          viewportBounds={viewportBounds}
   182→          spatialIndex={spatialIndex}
   183→          hoveredTaskId={hoveredTaskId}
   184→          selectedTaskId={selectedTaskId}
   185→          focusedTaskId={focusedTaskId}
   186→        />
   187→      )}
   188→      {opacities.micro > 0 && (
   189→        <MicroLayer
   190→          tasks={tasks}
   191→          trainCount={trainCount}
   192→          opacity={opacities.micro}
   193→          viewportBounds={viewportBounds}
   194→          hoveredTaskId={hoveredTaskId}
   195→          selectedTaskId={selectedTaskId}
   196→          focusedTaskId={focusedTaskId}
   197→        />
   198→      )}
   199→    </group>
   200→  );
   201→}
   202→
   203→/**
   204→ * Navigation target for programmatic navigation
   205→ * Can specify trainIndex, dayOffset, or both
   206→ */
   207→export interface NavigationTarget {
   208→  /** Train index (0-based) to center on vertically */
   209→  trainIndex?: number;
   210→  /** Day offset from start date to center on horizontally */
   211→  dayOffset?: number;
   212→  /** Optional zoom level to set (defaults to current zoom) */
   213→  zoom?: number;
   214→}
   215→
   216→interface InfiniteCanvasProps {
   217→  zoom: number;
   218→  lod: LODLevel;
   219→  onZoomChange: (zoom: number) => void;
   220→  /**
   221→   * Called when viewport position changes.
   222→   * @param viewport - Object with topY, leftX, rightX coordinates
   223→   */
   224→  onViewportChange?: (viewport: ViewportInfo) => void;
   225→  /**
   226→   * Called when the effective minimum zoom changes.
   227→   * Used by parent to enforce zoom limits on buttons.
   228→   */
   229→  onMinZoomChange?: (minZoom: number) => void;
   230→  /**
   231→   * Request a smooth animated zoom to target level.
   232→   * Called by parent buttons for +/- zoom with animation.
   233→   */
   234→  animatedZoomTarget?: number | null;
   235→  /**
   236→   * Called when animated zoom completes or is acknowledged.
   237→   */
   238→  onAnimatedZoomComplete?: () => void;
   239→  /**
   240→   * Request navigation to a specific train/date.
   241→   * Set to null after navigation completes.
   242→   */
   243→  navigationTarget?: NavigationTarget | null;
   244→  /**
   245→   * Called when navigation animation completes.
   246→   */
   247→  onNavigationComplete?: () => void;
   248→  /**
   249→   * Whether performance monitor panel is visible (PERF-001)
   250→   */
   251→  perfVisible?: boolean;
   252→  /**
   253→   * Current performance event type for logging context (PERF-001)
   254→   */
   255→  perfEvent?: PerfEvent;
   256→}
   257→
   258→// Navigation limits
   259→const ABSOLUTE_MIN_ZOOM = 0.05; // Absolute minimum to prevent extreme zoom out
   260→const MAX_ZOOM = 5.0;
   261→
   262→// Momentum physics constants
   263→const MOMENTUM_FRICTION = 0.93; // Per-frame velocity multiplier (0.93-0.95 recommended)
   264→const MOMENTUM_MIN_VELOCITY = 0.5; // Stop threshold in world units
   265→const MOMENTUM_VELOCITY_SAMPLES = 5; // Number of velocity samples to average
   266→
   267→// Smooth zoom constants
   268→const ZOOM_ANIMATION_DURATION = 250; // ms for animated zoom transitions
   269→const ZOOM_ACCUMULATION_TIMEOUT = 50; // ms to accumulate wheel events (trackpad smoothing)
   270→const PINCH_ZOOM_SENSITIVITY = 0.01; // Sensitivity for pinch-to-zoom
   271→
   272→// Cross-platform scroll normalization constants (F121)
   273→// Based on Facebook's normalizeWheel pattern and UX_RESEARCH.md
   274→const LINE_HEIGHT = 40; // Pixels per line (for deltaMode === 1)
   275→const PAGE_HEIGHT = 800; // Pixels per page (for deltaMode === 2)
   276→const MOUSE_ZOOM_SENSITIVITY = 0.003; // Base zoom sensitivity for mouse wheel
   277→const TRACKPAD_ZOOM_SENSITIVITY = 0.001; // Lower sensitivity for trackpad (many small events)
   278→const MAX_ZOOM_DELTA_PER_EVENT = 0.5; // Cap zoom change per event to prevent jumps
   279→const TRACKPAD_DETECTION_THRESHOLD = 20; // ms - events faster than this are trackpad
   280→const TRACKPAD_EVENT_COUNT_THRESHOLD = 3; // Number of rapid events to confirm trackpad
   281→
   282→// Scroll modifier pan sensitivity (F016, F017)
   283→// Convert wheel delta (pixels) to camera pan (world units)
   284→const SCROLL_PAN_SENSITIVITY = 1.5;
   285→
   286→// Keyboard shortcuts constants (F027, F028)
   287→const KEYBOARD_ZOOM_STEP = 1.5; // Zoom multiplier per keypress (1.5x = 150%)
   288→const KEYBOARD_PAN_STEP = 100; // Pixels to pan per arrow key press (in world units)
   289→const KEYBOARD_PAGE_STEP = 500; // Pixels for Page Up/Down (in world units)
   290→
   291→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
   292→
   293→/**
   294→ * Velocity sample for momentum calculation
   295→ * (Local type - only used for velocity tracking refs, not persisted state)
   296→ */
   297→interface VelocitySample {
   298→  x: number;
   299→  y: number;
   300→  time: number;
   301→}
   302→
   303→/**
   304→ * Local momentum animation state (includes animationId which is not in store)
   305→ * The actual momentum velocity is managed in canvasStore.viewport.momentum
   306→ */
   307→interface LocalMomentumState {
   308→  animationId: number | null;
   309→}
   310→
   311→/**
   312→ * Local zoom animation state (includes animationId)
   313→ * Animation parameters are stored in canvasStore.viewport.animation
   314→ */
   315→interface LocalZoomAnimationState {
   316→  animationId: number | null;
   317→}
   318→
   319→/**
   320→ * Pinch-to-zoom state for touch gestures
   321→ */
   322→interface PinchState {
   323→  active: boolean;
   324→  initialDistance: number;
   325→  initialZoom: number;
   326→  centerX: number;
   327→  centerY: number;
   328→  pointers: Map<number, { x: number; y: number }>;
   329→}
   330→
   331→/**
   332→ * Easing functions for smooth animations
   333→ * quadOut provides Google Maps-style smooth deceleration
   334→ */
   335→const Easing = {
   336→  quadOut: (t: number) => t * (2 - t),
   337→  cubicOut: (t: number) => 1 - Math.pow(1 - t, 3),
   338→};
   339→
   340→// Task block dimensions for hit testing (matching MesoLayer)
   341→const TASK_HEIGHT = pxPerTrain - 4;
   342→
   343→// ─────────────────────────────────────────────────────────────
   344→// KEYBOARD NAVIGATION HELPERS (F021)
   345→// ─────────────────────────────────────────────────────────────
   346→
   347→/**
   348→ * Get tasks visible within the current viewport
   349→ * Sorted by train index (Y) then start day (X) for logical tab order
   350→ */
   351→function getVisibleTasks(
   352→  tasks: ReturnType<typeof getRenderData>['tasks'],
   353→  viewportBounds: ViewportBounds
   354→): ReturnType<typeof getRenderData>['tasks'] {
   355→  const visibleTasks = tasks.filter((task) => {
   356→    const taskStartX = task.startDay * pxPerDay;
   357→    const taskEndX = taskStartX + task.duration * pxPerDay;
   358→    const taskY = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   359→
   360→    // Check if task overlaps with viewport
   361→    const xOverlap = taskEndX >= viewportBounds.minX && taskStartX <= viewportBounds.maxX;
   362→    const yOverlap = taskY >= viewportBounds.minY - pxPerTrain && taskY <= viewportBounds.maxY + pxPerTrain;
   363→
   364→    return xOverlap && yOverlap;
   365→  });
   366→
   367→  // Sort by train index (row), then by start day (column) for natural reading order
   368→  return visibleTasks.sort((a, b) => {
   369→    if (a.trainIndex !== b.trainIndex) {
   370→      return a.trainIndex - b.trainIndex;
   371→    }
   372→    return a.startDay - b.startDay;
   373→  });
   374→}
   375→
   376→/**
   377→ * Find next task in a specific direction from the current focused task
   378→ * Direction: 'left' | 'right' | 'up' | 'down'
   379→ */
   380→function findNextTaskInDirection(
   381→  tasks: ReturnType<typeof getRenderData>['tasks'],
   382→  currentTaskId: string,
   383→  direction: 'left' | 'right' | 'up' | 'down'
   384→): string | null {
   385→  const currentTask = tasks.find((t) => t.id === currentTaskId);
   386→  if (!currentTask) return null;
   387→
   388→  const currentX = currentTask.startDay * pxPerDay + (currentTask.duration * pxPerDay) / 2;
   389→  const currentY = -currentTask.trainIndex;
   390→
   391→  let bestMatch: typeof currentTask | null = null;
   392→  let bestScore = Infinity;
   393→
   394→  for (const task of tasks) {
   395→    if (task.id === currentTaskId) continue;
   396→
   397→    const taskX = task.startDay * pxPerDay + (task.duration * pxPerDay) / 2;
   398→    const taskY = -task.trainIndex;
   399→
   400→    let isInDirection = false;
   401→    let score = 0;
   402→
   403→    switch (direction) {
   404→      case 'left':
   405→        isInDirection = taskX < currentX;
   406→        if (isInDirection) {
   407→          // Prefer same row, then closest to the left
   408→          const rowPenalty = Math.abs(taskY - currentY) * 10000;
   409→          score = (currentX - taskX) + rowPenalty;
   410→        }
   411→        break;
   412→      case 'right':
   413→        isInDirection = taskX > currentX;
   414→        if (isInDirection) {
   415→          const rowPenalty = Math.abs(taskY - currentY) * 10000;
   416→          score = (taskX - currentX) + rowPenalty;
   417→        }
   418→        break;
   419→      case 'up':
   420→        isInDirection = taskY > currentY;
   421→        if (isInDirection) {
   422→          // Prefer closest row above with similar X
   423→          const xPenalty = Math.abs(taskX - currentX) / 100;
   424→          score = (taskY - currentY) + xPenalty;
   425→        }
   426→        break;
   427→      case 'down':
   428→        isInDirection = taskY < currentY;
   429→        if (isInDirection) {
   430→          const xPenalty = Math.abs(taskX - currentX) / 100;
   431→          score = (currentY - taskY) + xPenalty;
   432→        }
   433→        break;
   434→    }
   435→
   436→    if (isInDirection && score < bestScore) {
   437→      bestScore = score;
   438→      bestMatch = task;
   439→    }
   440→  }
   441→
   442→  return bestMatch?.id || null;
   443→}
   444→
   445→/**
   446→ * Find task at screen position (hit testing for hover/click)
   447→ *
   448→ * Converts screen coordinates to world coordinates and finds
   449→ * which task (if any) is under the cursor.
   450→ *
   451→ * @param screenX - Screen X coordinate (e.g., clientX)
   452→ * @param screenY - Screen Y coordinate (e.g., clientY)
   453→ * @param containerRect - Container element bounding rect
   454→ * @param cameraX - Camera X position in world coordinates
   455→ * @param cameraY - Camera Y position in world coordinates
   456→ * @param zoom - Current zoom level
   457→ * @param canvasWidth - Canvas width in pixels
   458→ * @param canvasHeight - Canvas height in pixels
   459→ * @param tasks - Array of tasks to test against
   460→ * @returns Task ID if found, null otherwise
   461→ */
   462→function findTaskAtPosition(
   463→  screenX: number,
   464→  screenY: number,
   465→  containerRect: DOMRect,
   466→  cameraX: number,
   467→  cameraY: number,
   468→  zoom: number,
   469→  canvasWidth: number,
   470→  canvasHeight: number,
   471→  tasks: ReturnType<typeof getRenderData>['tasks']
   472→): string | null {
   473→  // Convert screen coords to canvas coords (relative to container)
   474→  const canvasX = screenX - containerRect.left;
   475→  const canvasY = screenY - containerRect.top;
   476→
   477→  // Calculate half viewport in world units
   478→  const halfViewX = canvasWidth / 2 / zoom;
   479→  const halfViewY = canvasHeight / 2 / zoom;
   480→
   481→  // Convert canvas coords to world coords
   482→  // canvasX=0 is left edge of viewport, which is cameraX - halfViewX in world
   483→  // canvasY=0 is top edge of viewport, which is cameraY + halfViewY in world
   484→  const worldX = cameraX - halfViewX + (canvasX / zoom);
   485→  const worldY = cameraY + halfViewY - (canvasY / zoom);
   486→
   487→  // Find task at world position
   488→  for (const task of tasks) {
   489→    const taskStartX = task.startDay * pxPerDay;
   490→    const taskEndX = taskStartX + task.duration * pxPerDay;
   491→    const taskCenterY = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   492→    const taskTopY = taskCenterY + TASK_HEIGHT / 2;
   493→    const taskBottomY = taskCenterY - TASK_HEIGHT / 2;
   494→
   495→    if (
   496→      worldX >= taskStartX &&
   497→      worldX <= taskEndX &&
   498→      worldY <= taskTopY &&
   499→      worldY >= taskBottomY
   500→    ) {
   501→      return task.id;
   502→    }
   503→  }
   504→
   505→  return null;
   506→}
   507→
   508→/**
   509→ * Camera controller component (inside R3F context)
   510→ * Handles initial positioning and syncs camera with external state
   511→ *
   512→ * IMPORTANT: Uses R3F's `size` from useThree() which is the actual canvas size,
   513→ * not the container div size (which can differ due to flexbox/layout).
   514→ */
   515→function CameraController({
   516→  cameraX,
   517→  cameraY,
   518→  zoom,
   519→  worldBounds,
   520→  isInitialized,
   521→  onInitialized,
   522→  onViewportChange,
   523→}: {
   524→  cameraX: number;
   525→  cameraY: number;
   526→  zoom: number;
   527→  worldBounds: WorldBounds;
   528→  isInitialized: boolean;
   529→  onInitialized: (pos: { x: number; y: number }, size: { width: number; height: number }) => void;
   530→  onViewportChange?: (viewport: ViewportInfo) => void;
   531→}) {
   532→  const { camera, size } = useThree();
   533→
   534→  // Initialize camera position on first render using actual R3F size
   535→  useEffect(() => {
   536→    if (isInitialized || size.width === 0 || size.height === 0) return;
   537→
   538→    const halfViewX = size.width / 2 / zoom;
   539→    const halfViewY = size.height / 2 / zoom;
   540→
   541→    // Position camera to show top-left corner (X=0, Y=0)
   542→    const initialCameraX = halfViewX;
   543→    const initialCameraY = -halfViewY;
   544→
   545→    // Clamp to world bounds
   546→    const minCameraX = worldBounds.minX + halfViewX;
   547→    const maxCameraX = worldBounds.maxX - halfViewX;
   548→    const minCameraY = worldBounds.minY + halfViewY;
   549→    const maxCameraY = worldBounds.maxY - halfViewY;
   550→
   551→    const clampedX = Math.max(minCameraX, Math.min(maxCameraX, initialCameraX));
   552→    const clampedY = Math.max(minCameraY, Math.min(maxCameraY, initialCameraY));
   553→
   554→    // Update camera
   555→    camera.position.x = clampedX;
   556→    camera.position.y = clampedY;
   557→    (camera as any).zoom = zoom;
   558→    camera.updateProjectionMatrix();
   559→
   560→    // Notify parent of initial position and actual canvas size
   561→    onInitialized({ x: clampedX, y: clampedY }, { width: size.width, height: size.height });
   562→
   563→    // Notify viewport change with full viewport info
   564→    const topY = clampedY + halfViewY;
   565→    const leftX = clampedX - halfViewX;
   566→    const rightX = clampedX + halfViewX;
   567→    onViewportChange?.({ topY, leftX, rightX });
   568→  }, [size, zoom, worldBounds, camera, isInitialized, onInitialized, onViewportChange]);
   569→
   570→  // Sync camera with external state changes (after initialization)
   571→  useEffect(() => {
   572→    if (!isInitialized) return;
   573→
   574→    camera.position.x = cameraX;
   575→    camera.position.y = cameraY;
   576→    (camera as any).zoom = zoom;
   577→    camera.updateProjectionMatrix();
   578→  }, [camera, cameraX, cameraY, zoom, isInitialized]);
   579→
   580→  return null;
   581→}
   582→
   583→// ─────────────────────────────────────────────────────────────
   584→// ARIA LABELS FOR ACCESSIBILITY (F022)
   585→// ─────────────────────────────────────────────────────────────
   586→
   587→/**
   588→ * Human-readable LOD level names for screen reader announcements
   589→ */
   590→const LOD_LABELS: Record<LODLevel, string> = {
   591→  MACRO: 'Strategic view showing 10-year overview with heatmap',
   592→  MESO: 'Tactical view showing task blocks across trains',
   593→  MICRO: 'Detailed view showing individual task cards',
   594→};
   595→
   596→/**
   597→ * Format zoom level for screen reader announcement
   598→ */
   599→function formatZoomForAria(zoom: number): string {
   600→  const percentage = Math.round(zoom * 100);
   601→  return `${percentage} percent zoom`;
   602→}
   603→
   604→export function InfiniteCanvas({
   605→  zoom,
   606→  lod,
   607→  onZoomChange,
   608→  onViewportChange,
   609→  onMinZoomChange,
   610→  animatedZoomTarget,
   611→  onAnimatedZoomComplete,
   612→  navigationTarget,
   613→  onNavigationComplete,
   614→  perfVisible = false,
   615→  perfEvent = 'idle',
   616→}: InfiniteCanvasProps) {
   617→  const containerRef = useRef<HTMLDivElement>(null);
   618→
   619→  // ─────────────────────────────────────────────────────────────
   620→  // ARIA LIVE REGION STATE (F022)
   621→  // ─────────────────────────────────────────────────────────────
   622→  const ariaLiveRef = useRef<HTMLDivElement>(null);
   623→  const previousLodRef = useRef<LODLevel>(lod);
   624→  const previousZoomRef = useRef<number>(zoom);
   625→  const zoomAnnouncementTimeoutRef = useRef<number | null>(null);
   626→
   627→  // ─────────────────────────────────────────────────────────────
   628→  // STATE FROM CANVAS MACHINE (replaces useState)
   629→  // Using useSyncExternalStore under the hood - no stale closures!
   630→  // ─────────────────────────────────────────────────────────────
   631→  const isInitialized = useCanvasSelector((s) => s.viewport.isInitialized);
   632→  const canvasSize = useCanvasSelector((s) => s.viewport.canvasSize);
   633→  const cameraPos = useCanvasSelector((s) => s.viewport.camera);
   634→  const isPanning = useCanvasSelector((s) => s.viewport.isPanning);
   635→  const panStart = useCanvasSelector((s) => s.viewport.panStart);
   636→  const cameraPosAtPanStart = useCanvasSelector((s) => s.viewport.cameraPosAtPanStart);
   637→  const momentum = useCanvasSelector((s) => s.viewport.momentum);
   638→
   639→  // Interaction state (F018 hover, F019 selection)
   640→  const hoveredTaskId = useCanvasSelector((s) => s.interaction.hoveredTaskId);
   641→  const selectedTaskId = useCanvasSelector((s) => s.interaction.selectedTaskId);
   642→  const focusedTaskId = useCanvasSelector((s) => s.interaction.focusedTaskId);
   643→  const isHoverable = useCanvasSelector((s) => s.interaction.isHoverable);
   644→
   645→  // Get render data (memoized)
   646→  const { trains, tasks } = useMemo(() => getRenderData(), []);
   647→
   648→  // Build spatial index for viewport culling (PERF-002)
   649→  const spatialIndex = useSpatialIndex(tasks);
   650→
   651→  // Calculate world bounds (for pan clamping)
   652→  const worldBounds = useMemo<WorldBounds>(() => {
   653→    const totalDays = 365 * 10; // 10 years
   654→    return calculateWorldBounds(trains.length, totalDays);
   655→  }, [trains.length]);
   656→
   657→  /**
   658→   * Calculate dynamic MIN_ZOOM to prevent white space around content.
   659→   * MIN_ZOOM is set so the viewport never exceeds the world bounds.
   660→   */
   661→  const effectiveMinZoom = useMemo(() => {
   662→    if (canvasSize.width === 0 || canvasSize.height === 0) {
   663→      return ABSOLUTE_MIN_ZOOM;
   664→    }
   665→
   666→    const worldWidth = worldBounds.maxX - worldBounds.minX;
   667→    const worldHeight = Math.abs(worldBounds.maxY - worldBounds.minY);
   668→
   669→    // Calculate zoom levels where viewport equals world dimensions
   670→    // At zoom Z: viewportWidth = canvasSize.width / Z
   671→    // To fit world: canvasSize.width / Z = worldWidth → Z = canvasSize.width / worldWidth
   672→    const minZoomX = canvasSize.width / worldWidth;
   673→    const minZoomY = canvasSize.height / worldHeight;
   674→
   675→    // Use the maximum to ensure content fills viewport in both dimensions
   676→    const dynamicMin = Math.max(minZoomX, minZoomY);
   677→
   678→    // Clamp to absolute minimum (safety) and return
   679→    return Math.max(ABSOLUTE_MIN_ZOOM, dynamicMin);
   680→  }, [canvasSize.width, canvasSize.height, worldBounds]);
   681→
   682→  // Notify parent when effective min zoom changes
   683→  useEffect(() => {
   684→    onMinZoomChange?.(effectiveMinZoom);
   685→  }, [effectiveMinZoom, onMinZoomChange]);
   686→
   687→  // ─────────────────────────────────────────────────────────────
   688→  // ARIA ANNOUNCEMENTS (F022)
   689→  // ─────────────────────────────────────────────────────────────
   690→
   691→  /**
   692→   * Announce message to screen readers via ARIA live region
   693→   */
   694→  const announceToScreenReader = useCallback((message: string) => {
   695→    if (ariaLiveRef.current) {
   696→      // Clear and set to trigger announcement even for same message
   697→      ariaLiveRef.current.textContent = '';
   698→      // Use setTimeout to ensure the clear is processed first
   699→      setTimeout(() => {
   700→        if (ariaLiveRef.current) {
   701→          ariaLiveRef.current.textContent = message;
   702→        }
   703→      }, 50);
   704→    }
   705→  }, []);
   706→
   707→  // Announce LOD level changes
   708→  useEffect(() => {
   709→    if (lod !== previousLodRef.current) {
   710→      previousLodRef.current = lod;
   711→      announceToScreenReader(`View changed to ${LOD_LABELS[lod]}`);
   712→    }
   713→  }, [lod, announceToScreenReader]);
   714→
   715→  // Announce significant zoom changes (debounced to avoid spam)
   716→  useEffect(() => {
   717→    // Only announce if zoom changed significantly (>10%)
   718→    const zoomDiff = Math.abs(zoom - previousZoomRef.current) / previousZoomRef.current;
   719→    if (zoomDiff < 0.1) return;
   720→
   721→    // Clear previous timeout
   722→    if (zoomAnnouncementTimeoutRef.current) {
   723→      clearTimeout(zoomAnnouncementTimeoutRef.current);
   724→    }
   725→
   726→    // Debounce zoom announcements (wait 500ms after last change)
   727→    zoomAnnouncementTimeoutRef.current = window.setTimeout(() => {
   728→      previousZoomRef.current = zoom;
   729→      announceToScreenReader(formatZoomForAria(zoom));
   730→    }, 500);
   731→
   732→    return () => {
   733→      if (zoomAnnouncementTimeoutRef.current) {
   734→        clearTimeout(zoomAnnouncementTimeoutRef.current);
   735→      }
   736→    };
   737→  }, [zoom, announceToScreenReader]);
   738→
   739→  // ─────────────────────────────────────────────────────────────
   740→  // LOCAL REFS (animation frame IDs, velocity samples - not state)
   741→  // These are not state because they don't affect rendering
   742→  // ─────────────────────────────────────────────────────────────
   743→  const velocitySamplesRef = useRef<VelocitySample[]>([]);
   744→  const momentumAnimationRef = useRef<LocalMomentumState>({
   745→    animationId: null,
   746→  });
   747→  const lastPointerPosRef = useRef({ x: 0, y: 0, time: 0 });
   748→  // Track if pointer moved significantly (to distinguish click from pan)
   749→  const pointerMovedRef = useRef(false);
   750→  const pointerDownPosRef = useRef({ x: 0, y: 0 });
   751→
   752→  // Smooth zoom animation state - only the animationId is local
   753→  // Animation parameters are now in canvasStore.viewport.animation
   754→  const zoomAnimationRef = useRef<LocalZoomAnimationState>({
   755→    animationId: null,
   756→  });
   757→
   758→  // Wheel event accumulation for trackpad smooth zoom + input detection (F121)
   759→  const wheelAccumulatorRef = useRef({
   760→    delta: 0,
   761→    cursorX: 0,
   762→    cursorY: 0,
   763→    timeout: null as ReturnType<typeof setTimeout> | null,
   764→    // Trackpad detection state
   765→    lastEventTime: 0,
   766→    rapidEventCount: 0,
   767→    isTrackpad: false,
   768→  });
   769→
   770→  // Pinch-to-zoom state
   771→  const pinchRef = useRef<PinchState>({
   772→    active: false,
   773→    initialDistance: 0,
   774→    initialZoom: 1,
   775→    centerX: 0,
   776→    centerY: 0,
   777→    pointers: new Map(),
   778→  });
   779→
   780→  /**
   781→   * Update camera position in the canvas store
   782→   * Using external store means no stale closures - getState() always returns current value
   783→   */
   784→  const updateCameraPos = useCallback((pos: { x: number; y: number }) => {
   785→    canvasStore.dispatch(canvasActions.viewport.setCamera(pos));
   786→  }, []);
   787→
   788→  /**
   789→   * Called by CameraController when it initializes with actual R3F canvas size
   790→   */
   791→  const handleCameraInitialized = useCallback(
   792→    (pos: { x: number; y: number }, size: { width: number; height: number }) => {
   793→      canvasStore.dispatch(
   794→        canvasActions.viewport.initialize({ camera: pos, canvasSize: size })
   795→      );
   796→    },
   797→    []
   798→  );
   799→
   800→  /**
   801→   * Calculate and notify the viewport position (topY, leftX, rightX)
   802→   */
   803→  const notifyViewportChange = useCallback(
   804→    (camX: number, camY: number, currentZoom: number) => {
   805→      const halfViewX = canvasSize.width / 2 / currentZoom;
   806→      const halfViewY = canvasSize.height / 2 / currentZoom;
   807→      const topY = camY + halfViewY;
   808→      const leftX = camX - halfViewX;
   809→      const rightX = camX + halfViewX;
   810→      onViewportChange?.({ topY, leftX, rightX });
   811→    },
   812→    [canvasSize.width, canvasSize.height, onViewportChange]
   813→  );
   814→
   815→  /**
   816→   * Calculate viewport bounds for frustum culling
   817→   * This determines which tasks are visible and need to be rendered
   818→   * IMPORTANT: Must be defined before handleKeyDown which uses it for F021
   819→   */
