const CELL_WIDTH = DAYS_PER_CELL * pxPerDay; // 300px
const CELL_HEIGHT = pxPerTrain; // 24px per train row
const CELL_GAP = 1; // Small gap between cells

// Heatmap color gradient: yellow → orange → red
