  if (totalCells === 0) {
    return null;
  }

  return (
    <group>
      {/* Heatmap cells */}
      <instancedMesh
        ref={meshRef}
        args={[undefined, undefined, totalCells]}
      >
        <planeGeometry args={[1, 1]} />
        <meshBasicMaterial
          toneMapped={false}
          transparent={opacity < 1}
          opacity={opacity}
        />
      </instancedMesh>

      {/* Year markers (vertical lines) */}
