/**
 * EntityStore - STATE-ARCH-001 Phase 1
 *
 * High-performance TypedArray-based entity storage using Structure of Arrays (SoA).
 * Optimized for WebGL rendering with zero GC pressure in hot path.
 *
 * Key features:
 * - TypedArrays for numeric data (cache-friendly iteration)
 * - Bulk loading optimized for initial data
 * - Cursor-based access (zero-allocation reads)
 * - Direct mutation (no Proxy overhead)
 *
 * Performance targets:
 * - 100k entities in ~1.7MB
 * - Zero GC during pan/zoom
 * - <1ms for bulk load of 5k entities
 */

import { DEFAULT_VIEW_CONFIG } from '../data/types';
import type {
  IEntityStore,
  TaskArrays,
  TaskStringData,
  TaskData,
  TaskCursor,
  TaskTypeValue,
  TaskColorValue,
} from './types';
import {
  TASK_TYPE_TO_VALUE,
  VALUE_TO_TASK_TYPE,
  TASK_COLOR_TO_VALUE,
  VALUE_TO_TASK_COLOR,
} from './types';

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;

/**
 * Default initial capacity (will grow if needed)
 */
const DEFAULT_CAPACITY = 10000;

/**
 * Growth factor when arrays need to be resized
 */
const GROWTH_FACTOR = 1.5;

/**
 * Create TaskArrays with given capacity
 */
function createArrays(capacity: number): TaskArrays {
  return {
    startDay: new Float32Array(capacity),
    duration: new Float32Array(capacity),
    trainIndex: new Uint16Array(capacity),
    type: new Uint8Array(capacity),
    color: new Uint8Array(capacity),
    hasConflict: new Uint8Array(capacity),
    predecessorIndex: new Int32Array(capacity).fill(-1),
  };
}

/**
 * Resize arrays to new capacity, preserving existing data
 */
function resizeArrays(
  oldArrays: TaskArrays,
  oldCount: number,
  newCapacity: number
): TaskArrays {
  const newArrays = createArrays(newCapacity);

  // Copy existing data
  newArrays.startDay.set(oldArrays.startDay.subarray(0, oldCount));
  newArrays.duration.set(oldArrays.duration.subarray(0, oldCount));
  newArrays.trainIndex.set(oldArrays.trainIndex.subarray(0, oldCount));
  newArrays.type.set(oldArrays.type.subarray(0, oldCount));
  newArrays.color.set(oldArrays.color.subarray(0, oldCount));
  newArrays.hasConflict.set(oldArrays.hasConflict.subarray(0, oldCount));
  newArrays.predecessorIndex.set(oldArrays.predecessorIndex.subarray(0, oldCount));

  return newArrays;
}

/**
 * TaskCursor implementation - lightweight view into arrays
 */
class TaskCursorImpl implements TaskCursor {
  constructor(
    private readonly store: EntityStore,
    public readonly index: number
  ) {}

  get id(): string {
    return this.store.strings.ids.get(this.index) ?? '';
  }

  get startDay(): number {
    return this.store.arrays.startDay[this.index];
  }

  get duration(): number {
    return this.store.arrays.duration[this.index];
  }

  get trainIndex(): number {
    return this.store.arrays.trainIndex[this.index];
  }

  get typeValue(): TaskTypeValue {
    return this.store.arrays.type[this.index] as TaskTypeValue;
  }

  get type(): string {
    return VALUE_TO_TASK_TYPE[this.typeValue];
  }

  get colorValue(): TaskColorValue {
    return this.store.arrays.color[this.index] as TaskColorValue;
  }

  get color(): string {
    return VALUE_TO_TASK_COLOR[this.colorValue];
  }

  get hasConflict(): boolean {
    return this.store.arrays.hasConflict[this.index] === 1;
  }

  get predecessorIndex(): number {
    return this.store.arrays.predecessorIndex[this.index];
  }

  get predecessorId(): string | undefined {
    const predIndex = this.predecessorIndex;
    if (predIndex < 0) return undefined;
    return this.store.strings.ids.get(predIndex);
  }

  // Computed properties for rendering
  get x(): number {
    return this.startDay * pxPerDay;
  }

  get y(): number {
    return -this.trainIndex * pxPerTrain - pxPerTrain / 2;
  }

  get width(): number {
    return this.duration * pxPerDay;
  }
}

/**
 * EntityStore - High-performance SoA storage for task entities
 */
export class EntityStore implements IEntityStore {
  private _count: number = 0;
  private _capacity: number;
  private _arrays: TaskArrays;
  private _strings: TaskStringData;

  // Reusable cursor to avoid allocations in hot path
  private _cursor: TaskCursorImpl;

  constructor(initialCapacity: number = DEFAULT_CAPACITY) {
    this._capacity = initialCapacity;
    this._arrays = createArrays(initialCapacity);
    this._strings = {
      ids: new Map(),
      idToIndex: new Map(),
    };
    this._cursor = new TaskCursorImpl(this, 0);
  }

  get count(): number {
    return this._count;
  }

  get capacity(): number {
    return this._capacity;
  }

  get arrays(): TaskArrays {
    return this._arrays;
  }

  get strings(): TaskStringData {
    return this._strings;
  }

  /**
   * Ensure capacity for at least `minCapacity` entities
   */
  private ensureCapacity(minCapacity: number): void {
    if (minCapacity <= this._capacity) return;

    // Grow by factor or to minCapacity, whichever is larger
    const newCapacity = Math.max(
      Math.ceil(this._capacity * GROWTH_FACTOR),
      minCapacity
    );

    this._arrays = resizeArrays(this._arrays, this._count, newCapacity);
    this._capacity = newCapacity;
  }

  /**
   * Load entities from array of task objects (bulk load)
   * Optimized for initial data loading
   */
  load(tasks: TaskData[]): void {
    const startTime = performance.now();

    // Ensure capacity
    this.ensureCapacity(tasks.length);

    // First pass: load all data and build ID map
    for (let i = 0; i < tasks.length; i++) {
      const task = tasks[i];

      this._arrays.startDay[i] = task.startDay;
      this._arrays.duration[i] = task.duration;
      this._arrays.trainIndex[i] = task.trainIndex;
      this._arrays.type[i] = TASK_TYPE_TO_VALUE[task.type];
      this._arrays.color[i] = TASK_COLOR_TO_VALUE[task.color];
      this._arrays.hasConflict[i] = task.hasConflict ? 1 : 0;
      this._arrays.predecessorIndex[i] = -1; // Set in second pass

      this._strings.ids.set(i, task.id);
      this._strings.idToIndex.set(task.id, i);
    }

    // Second pass: resolve predecessor IDs to indices
    for (let i = 0; i < tasks.length; i++) {
      const task = tasks[i];
      if (task.predecessorId) {
        const predIndex = this._strings.idToIndex.get(task.predecessorId);
        if (predIndex !== undefined) {
          this._arrays.predecessorIndex[i] = predIndex;
        }
      }
    }

    this._count = tasks.length;

    const elapsed = performance.now() - startTime;
    console.log(`[EntityStore] Loaded ${tasks.length} entities in ${elapsed.toFixed(2)}ms`);
  }

  /**
   * Get task data by index
   * Returns a cursor that reads directly from arrays
   *
   * IMPORTANT: The returned cursor is reused - do not store references
   */
  get(index: number): TaskCursor {
    if (index < 0 || index >= this._count) {
      throw new RangeError(`Index ${index} out of bounds (count: ${this._count})`);
    }

    // Reuse cursor object to avoid allocation
    (this._cursor as any).index = index;
    return this._cursor;
  }

  /**
   * Get task data by ID
   * Returns null if not found
   */
  getById(id: string): TaskCursor | null {
    const index = this._strings.idToIndex.get(id);
    if (index === undefined) return null;
    return this.get(index);
  }

  /**
   * Get a NEW cursor for the given index
   * Use this when you need to store the cursor reference
   */
  getCursor(index: number): TaskCursor {
    if (index < 0 || index >= this._count) {
      throw new RangeError(`Index ${index} out of bounds (count: ${this._count})`);
    }
    return new TaskCursorImpl(this, index);
  }

  /**
   * Clear all entities
   */
  clear(): void {
    this._count = 0;
    this._strings.ids.clear();
    this._strings.idToIndex.clear();
    // Note: We don't reallocate arrays - just reset count
  }

  /**
   * Iterator over all valid entities
   * Yields fresh cursors (safe to store)
   */
  *[Symbol.iterator](): Iterator<TaskCursor> {
    for (let i = 0; i < this._count; i++) {
      yield new TaskCursorImpl(this, i);
    }
  }

  /**
   * Memory usage estimate in bytes
   */
  getMemoryUsage(): number {
    const arrayBytes =
      this._arrays.startDay.byteLength +
      this._arrays.duration.byteLength +
      this._arrays.trainIndex.byteLength +
      this._arrays.type.byteLength +
      this._arrays.color.byteLength +
      this._arrays.hasConflict.byteLength +
      this._arrays.predecessorIndex.byteLength;

    // Estimate string storage (rough approximation)
    const avgIdLength = 15; // e.g., "TRAIN-001-2024-5"
    const stringBytes = this._count * avgIdLength * 2; // UTF-16

    return arrayBytes + stringBytes;
  }

  /**
   * Log memory usage stats
   */
  logMemoryStats(): void {
    const bytes = this.getMemoryUsage();
    const kb = bytes / 1024;
    const mb = kb / 1024;

    console.log(`[EntityStore] Memory usage:`);
    console.log(`  Entities: ${this._count}`);
    console.log(`  Capacity: ${this._capacity}`);
    console.log(`  Memory: ${mb.toFixed(2)} MB (${kb.toFixed(0)} KB)`);
    console.log(`  Bytes per entity: ${(bytes / this._count).toFixed(1)}`);
  }
}

/**
 * Singleton instance for global access
 * Use this for the main task store
 */
let globalStore: EntityStore | null = null;

/**
 * Get or create the global EntityStore instance
 */
export function getEntityStore(): EntityStore {
  if (!globalStore) {
    globalStore = new EntityStore();
  }
  return globalStore;
}

/**
 * Reset the global store (for testing)
 */
export function resetEntityStore(): void {
  globalStore = null;
}

